import 'package:firebase_auth/firebase_auth.dart'; import 'package:injectable/injectable.dart'; import '../../../core/utils/app_logger.dart'; @injectable class EmailVerificationService { Future<void> sendVerification() async { try { await FirebaseAuth.instance.currentUser?.sendEmailVerification(); AppLogger.info('Verification email sent'); } catch (e) { AppLogger.error('Email verification failed', e); } } bool isVerified() => FirebaseAuth.instance.currentUser?.emailVerified ?? false; Future<void> reload() => FirebaseAuth.instance.currentUser!.reload(); }